#!/usr/bin/env python3
from __future__ import annotations

import importlib.util
import json
import struct
import sys
import tempfile
import unittest
from pathlib import Path

import numpy as np


SCRIPT_PATH = Path(__file__).resolve().parents[1] / "flux-knot-diffusers.py"
SPEC = importlib.util.spec_from_file_location("flux_knot_diffusers", SCRIPT_PATH)
assert SPEC is not None
flux_bridge = importlib.util.module_from_spec(SPEC)
assert SPEC.loader is not None
sys.modules[SPEC.name] = flux_bridge
SPEC.loader.exec_module(flux_bridge)


def write_knot(path: Path, metadata: dict, payload: bytes = b"") -> None:
    meta = json.dumps(metadata).encode()
    header = b"KNOT" + struct.pack("<H", 1) + struct.pack("<I", len(meta)) + meta
    header += b"\x00" * ((-len(header)) % 4)
    header += b"\x20"
    path.write_bytes(header + payload)


def q8_0_encode(values: np.ndarray) -> bytes:
    flat = values.astype(np.float32).reshape(-1)
    pad = (-len(flat)) % 32
    if pad:
        flat = np.pad(flat, (0, pad))
    blocks = flat.reshape(-1, 32)
    scale = np.max(np.abs(blocks), axis=1) / 127.0
    inv = np.where(scale > 0, 1.0 / scale, 0.0)
    quantized = np.clip(np.round(blocks * inv[:, None]), -127, 127).astype(np.int8)
    out = bytearray()
    for block_scale, block_values in zip(scale.astype(np.float16), quantized):
        out.extend(block_scale.tobytes())
        out.extend(block_values.tobytes())
    return bytes(out)


class FluxKnotDiffusersBridgeTest(unittest.TestCase):
    def test_read_knot_header_accounts_for_padding_and_codec_marker(self) -> None:
        with tempfile.TemporaryDirectory() as tmp:
            path = Path(tmp) / "tiny.knot"
            metadata = {"arch": "flux", "config": {"arch": "flux"}, "tensors": {}}
            write_knot(path, metadata, b"payload")

            header = flux_bridge.read_knot_header(path)

        raw_meta = json.dumps(metadata).encode()
        expected = 10 + len(raw_meta)
        expected += (-expected) % 4
        expected += 1
        self.assertEqual(header.payload_offset, expected)
        self.assertEqual(header.metadata["arch"], "flux")

    def test_validate_requires_full_flux_component_policy_and_shapes(self) -> None:
        metadata = {
            "arch": "flux",
            "config": {"arch": "flux"},
            "components": {
                "policy": "flux-with-vae-text-encoders",
                "included": ["transformer", "vae", "text_encoder", "text_encoder_2"],
                "skipped": ["tokenizer", "tokenizer_2", "scheduler", "feature_extractor"],
            },
            "tensors": {
                "flux_img_in_weight.bin": {"offset": 0, "length": 4, "type": "F32", "shape": [1]},
                "flux_vae_decoder_conv_in_weight.bin": {
                    "offset": 4,
                    "length": 4,
                    "type": "F32",
                    "shape": [1],
                },
                "flux_clip_text_model_final_layer_norm_weight.bin": {
                    "offset": 8,
                    "length": 4,
                    "type": "F32",
                    "shape": [1],
                },
                "flux_t5_encoder_final_layer_norm_weight.bin": {
                    "offset": 12,
                    "length": 4,
                    "type": "F32",
                    "shape": [1],
                },
            },
        }

        self.assertEqual(flux_bridge.validate_flux_knot_metadata(metadata), [])

        del metadata["tensors"]["flux_t5_encoder_final_layer_norm_weight.bin"]["shape"]
        problems = flux_bridge.validate_flux_knot_metadata(metadata)

        self.assertTrue(any("text_encoder_2 tensors missing shape metadata" in p for p in problems))

    def test_dequantize_q8_0_round_trips_small_tensor(self) -> None:
        values = np.linspace(-1.0, 1.0, num=40, dtype=np.float32).reshape(5, 8)
        raw = q8_0_encode(values)

        restored = flux_bridge.dequantize_q8_0(raw, [5, 8])

        self.assertEqual(restored.shape, (5, 8))
        self.assertLess(np.max(np.abs(restored - values)), 0.01)

    def test_tensor_reader_reads_f32_and_q8_payloads(self) -> None:
        f32 = np.array([1.25, -2.5], dtype=np.float32)
        q8 = np.linspace(-0.5, 0.5, num=33, dtype=np.float32)
        payload = f32.tobytes() + q8_0_encode(q8)
        metadata = {
            "arch": "flux",
            "config": {"arch": "flux"},
            "tensors": {
                "a.bin": {"offset": 0, "length": f32.nbytes, "type": "F32", "shape": [2]},
                "b.bin": {
                    "offset": f32.nbytes,
                    "length": len(q8_0_encode(q8)),
                    "type": "Q8_0",
                    "shape": [33],
                },
            },
        }

        with tempfile.TemporaryDirectory() as tmp:
            path = Path(tmp) / "payload.knot"
            write_knot(path, metadata, payload)
            reader = flux_bridge.KnotTensorReader(path)
            loaded_f32 = reader.read_numpy("a.bin")
            loaded_q8 = reader.read_numpy("b.bin")

        np.testing.assert_allclose(loaded_f32, f32)
        self.assertLess(np.max(np.abs(loaded_q8 - q8)), 0.01)

    def test_diffusers_parameter_mapping_reuses_encoder_contract(self) -> None:
        encoder_module = flux_bridge.load_encode_knot_module()

        self.assertEqual(
            flux_bridge.diffusers_param_to_knot_key(encoder_module, "transformer", "img_in.weight"),
            None,
        )
        self.assertEqual(
            flux_bridge.diffusers_param_to_knot_key(
                encoder_module,
                "transformer",
                "x_embedder.weight",
            ),
            "flux_img_in_weight.bin",
        )
        self.assertEqual(
            flux_bridge.diffusers_param_to_knot_key(
                encoder_module,
                "vae",
                "decoder.conv_in.weight",
            ),
            "flux_vae_decoder_conv_in_weight.bin",
        )
        self.assertEqual(
            flux_bridge.diffusers_param_to_knot_key(
                encoder_module,
                "text_encoder",
                "text_model.final_layer_norm.weight",
            ),
            "flux_clip_text_model_final_layer_norm_weight.bin",
        )
        self.assertEqual(
            flux_bridge.diffusers_param_to_knot_key(
                encoder_module,
                "text_encoder_2",
                "encoder.final_layer_norm.weight",
            ),
            "flux_t5_encoder_final_layer_norm_weight.bin",
        )

    def test_transformer_mapping_splits_fused_double_block_qkv(self) -> None:
        plan = flux_bridge.transformer_param_to_knot_plan(
            "transformer_blocks.2.attn.to_k.weight"
        )
        self.assertIsNotNone(plan)
        self.assertEqual(plan.key, "flux_dbl_2_img_qkv_weight.bin")

        fused = np.arange(24, dtype=np.float32).reshape(6, 4)
        restored = flux_bridge.apply_tensor_plan(fused, plan, (2, 4))

        np.testing.assert_allclose(restored, fused[2:4])

    def test_transformer_mapping_splits_fused_single_block_linear1(self) -> None:
        plan = flux_bridge.transformer_param_to_knot_plan(
            "single_transformer_blocks.3.proj_mlp.bias"
        )
        self.assertIsNotNone(plan)
        self.assertEqual(plan.key, "flux_sgl_3_linear1_bias.bin")

        fused = np.arange(16, dtype=np.float32)
        restored = flux_bridge.apply_tensor_plan(fused, plan, (4,))

        np.testing.assert_allclose(restored, fused[12:16])

    def test_transformer_mapping_swaps_adaln_scale_shift(self) -> None:
        plan = flux_bridge.transformer_param_to_knot_plan("norm_out.linear.bias")
        self.assertIsNotNone(plan)
        self.assertEqual(plan.key, "flux_final_adaln_bias.bin")

        source = np.array([1.0, 2.0, 10.0, 20.0], dtype=np.float32)
        restored = flux_bridge.apply_tensor_plan(source, plan, (4,))

        np.testing.assert_allclose(restored, [10.0, 20.0, 1.0, 2.0])


if __name__ == "__main__":
    unittest.main()
